import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const Home = () => {
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [filteredVehicles, setFilteredVehicles] = useState([]);
  const [selectedType, setSelectedType] = useState("all");
  const [types, setTypes] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVehicles = async () => {
      try {
        setLoading(true);
        const res = await axios.get("http://localhost:8070/api/vehicles");

        const available = (res.data || []).filter(
          (v) => (v.status || "").toLowerCase() === "available"
        );

        setVehicles(available);
        setFilteredVehicles(available);

        const uniqueTypes = [
          ...new Set(available.map((v) => v.type).filter(Boolean)),
        ];
        setTypes(uniqueTypes);
      } finally {
        setLoading(false);
      }
    };

    fetchVehicles();
  }, []);

  const handleFilterChange = (e) => {
    const value = e.target.value;
    setSelectedType(value);

    if (value === "all") {
      setFilteredVehicles(vehicles);
    } else {
      setFilteredVehicles(vehicles.filter((v) => v.type === value));
    }
  };

  const stats = useMemo(() => {
    const total = vehicles.length;
    const totalValue = vehicles.reduce((sum, v) => sum + Number(v.price || 0), 0);
    const avgPrice = total ? totalValue / total : 0;

    return {
      total,
      types: types.length,
      totalValue,
      avgPrice,
    };
  }, [vehicles, types]);

  const featuredVehicles = filteredVehicles.slice(0, 3);

  return (
    <div style={{ backgroundColor: "var(--bg)" }}>
      {/* HERO SECTION */}
      <div style={{
        background: "linear-gradient(135deg, var(--primary) 0%, rgba(76, 175, 80, 0.8) 100%)",
        color: "white",
        padding: "80px 20px",
        textAlign: "center",
        marginBottom: 60
      }}>
        <div style={{ maxWidth: 900, margin: "0 auto" }}>
          <div style={{
            fontSize: "48px",
            fontWeight: 700,
            letterSpacing: "-0.5px",
            marginBottom: 16,
            lineHeight: 1.2
          }}>
            Find Your Perfect Vehicle
          </div>
          <div style={{
            fontSize: "18px",
            fontWeight: 300,
            opacity: 0.95,
            marginBottom: 32,
            lineHeight: 1.6
          }}>
            Browse our premium collection of available vehicles. Premium quality, trusted service, and exceptional value.
          </div>
          <div style={{ display: "flex", gap: 12, justifyContent: "center", flexWrap: "wrap" }}>
            <button onClick={() => navigate("/vehicles")} className="btn" style={{
              backgroundColor: "white",
              color: "var(--primary)",
              fontWeight: 600,
              padding: "12px 28px",
              fontSize: "15px"
            }}>
              Browse All Vehicles
            </button>
            <button onClick={() => navigate("/book-appointment")} className="btn" style={{
              backgroundColor: "rgba(255,255,255,0.2)",
              color: "white",
              border: "2px solid white",
              fontWeight: 600,
              padding: "12px 28px",
              fontSize: "15px"
            }}>
              Book Test Drive
            </button>
          </div>
        </div>
      </div>

      {/* STATS SECTION */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px", marginBottom: 60 }}>
        <div style={{ 
          display: "grid", 
          gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", 
          gap: 20 
        }}>
          <StatCard 
            number={loading ? "—" : stats.total} 
            label="Available Vehicles" 
            description="In our inventory" 
          />
          <StatCard 
            number={loading ? "—" : stats.types} 
            label="Vehicle Types" 
            description="Diverse selection" 
          />
          <StatCard 
            number={loading ? "—" : `LKR ${(stats.totalValue / 1000000).toFixed(1)}M`} 
            label="Total Value" 
            description="Combined inventory" 
          />
          <StatCard 
            number={loading ? "—" : `LKR ${Math.round(stats.avgPrice / 100000) * 100000 / 100000}`} 
            label="Avg. Price" 
            description="Market rate" 
          />
        </div>
      </div>

      {/* FEATURED VEHICLES */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px", marginBottom: 60 }}>
        <div style={{ marginBottom: 40 }}>
          <div style={{
            fontSize: "32px",
            fontWeight: 700,
            color: "var(--text)",
            marginBottom: 8
          }}>
            Featured Vehicles
          </div>
          <div style={{
            fontSize: "16px",
            color: "var(--text-light)",
            fontWeight: 300
          }}>
            Handpicked selection of our best available models
          </div>
        </div>

        {loading ? (
          <div style={{ textAlign: "center", padding: "60px 20px", color: "var(--text-light)" }}>
            Loading featured vehicles...
          </div>
        ) : featuredVehicles.length === 0 ? (
          <div style={{ textAlign: "center", padding: "60px 20px", color: "var(--text-light)" }}>
            No vehicles available currently
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fit, minmax(320px, 1fr))",
            gap: 24
          }}>
            {featuredVehicles.map((v) => (
              <VehicleCard key={v._id} vehicle={v} navigate={navigate} />
            ))}
          </div>
        )}
      </div>

      {/* FILTER AND BROWSE SECTION */}
      <div style={{ maxWidth: 1200, margin: "0 auto", padding: "0 20px", marginBottom: 60 }}>
        <div style={{ marginBottom: 32 }}>
          <div style={{
            fontSize: "32px",
            fontWeight: 700,
            color: "var(--text)",
            marginBottom: 8
          }}>
            Browse by Category
          </div>
          <div style={{
            fontSize: "16px",
            color: "var(--text-light)",
            fontWeight: 300
          }}>
            Filter vehicles by type to find exactly what you're looking for
          </div>
        </div>

        <div className="card cardPad" style={{ marginBottom: 32 }}>
          <select
            className="select"
            value={selectedType}
            onChange={handleFilterChange}
            style={{
              minWidth: 240,
              fontSize: 15,
              fontWeight: 500
            }}
          >
            <option value="all">All Vehicle Types</option>
            {types.map((t) => (
              <option key={t} value={t}>
                {t}
              </option>
            ))}
          </select>
          <div style={{
            marginLeft: 16,
            fontSize: "15px",
            color: "var(--text-light)",
            fontWeight: 500
          }}>
            Showing <b style={{ color: "var(--text)" }}>{filteredVehicles.length}</b> vehicle{filteredVehicles.length !== 1 ? "s" : ""}
          </div>
        </div>

        {/* VEHICLES GRID */}
        {loading ? (
          <div style={{ textAlign: "center", padding: "60px 20px", color: "var(--text-light)" }}>
            Loading inventory...
          </div>
        ) : filteredVehicles.length === 0 ? (
          <div style={{ textAlign: "center", padding: "60px 20px", color: "var(--text-light)" }}>
            No vehicles found for the selected type.
          </div>
        ) : (
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
            gap: 20
          }}>
            {filteredVehicles.map((v) => (
              <VehicleCard key={v._id} vehicle={v} navigate={navigate} />
            ))}
          </div>
        )}
      </div>

      {/* CTA FOOTER */}
      <div style={{
        background: "linear-gradient(135deg, var(--primary) 0%, rgba(76, 175, 80, 0.8) 100%)",
        color: "white",
        padding: "60px 20px",
        textAlign: "center",
        marginTop: 60
      }}>
        <div style={{ maxWidth: 600, margin: "0 auto" }}>
          <div style={{
            fontSize: "32px",
            fontWeight: 700,
            marginBottom: 16
          }}>
            Ready to Schedule a Test Drive?
          </div>
          <div style={{
            fontSize: "16px",
            fontWeight: 300,
            opacity: 0.9,
            marginBottom: 24,
            lineHeight: 1.6
          }}>
            Experience any of our vehicles firsthand. Our expert team is ready to assist you.
          </div>
          <button 
            onClick={() => navigate("/book-appointment")}
            className="btn" 
            style={{
              backgroundColor: "white",
              color: "var(--primary)",
              fontWeight: 600,
              padding: "14px 32px",
              fontSize: "16px"
            }}
          >
            Book Now
          </button>
        </div>
      </div>
    </div>
  );
};

function StatCard({ number, label, description }) {
  return (
    <div className="card cardPad" style={{
      textAlign: "center",
      border: "1px solid var(--border)",
      transition: "all 0.3s ease"
    }}>
      <div style={{
        fontSize: "28px",
        fontWeight: 700,
        color: "var(--primary)",
        marginBottom: 8
      }}>
        {number}
      </div>
      <div style={{
        fontSize: "15px",
        fontWeight: 600,
        color: "var(--text)",
        marginBottom: 4
      }}>
        {label}
      </div>
      <div style={{
        fontSize: "13px",
        color: "var(--text-light)",
        fontWeight: 300
      }}>
        {description}
      </div>
    </div>
  );
}

function VehicleCard({ vehicle: v, navigate }) {
  const imageUrl = v.images?.[0]?.url || "https://via.placeholder.com/400x250?text=No+Image";

  return (
    <div className="card" style={{
      overflow: "hidden",
      transition: "transform 0.3s ease, box-shadow 0.3s ease",
      cursor: "pointer"
    }}
    onMouseEnter={(e) => {
      e.currentTarget.style.transform = "translateY(-4px)";
      e.currentTarget.style.boxShadow = "0 12px 24px rgba(0,0,0,0.15)";
    }}
    onMouseLeave={(e) => {
      e.currentTarget.style.transform = "translateY(0)";
      e.currentTarget.style.boxShadow = "0 4px 12px rgba(0,0,0,0.1)";
    }}>
      {/* Image Section */}
      <div style={{
        width: "100%",
        height: "200px",
        overflow: "hidden",
        backgroundColor: "#f0f0f0",
        position: "relative"
      }}>
        <img 
          src={imageUrl}
          alt={`${v.brand} ${v.type}`}
          style={{
            width: "100%",
            height: "100%",
            objectFit: "cover",
            cursor: "pointer",
            transition: "transform 0.3s ease"
          }}
          onMouseEnter={(e) => e.currentTarget.style.transform = "scale(1.05)"}
          onMouseLeave={(e) => e.currentTarget.style.transform = "scale(1)"}
          onClick={() => navigate(`/vehicles/${v._id}`)}
        />
        {v.images && v.images.length > 1 && (
          <div style={{
            position: "absolute",
            bottom: 8,
            right: 8,
            backgroundColor: "rgba(0,0,0,0.6)",
            color: "white",
            padding: "4px 8px",
            borderRadius: "4px",
            fontSize: "12px",
            fontWeight: 600
          }}>
            +{v.images.length} photos
          </div>
        )}
      </div>

      <div className="cardPad" style={{ display: "flex", flexDirection: "column", gap: 16, height: "100%" }}>
        {/* Header */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12 }}>
          <div>
            <div style={{
              fontSize: "18px",
              fontWeight: 700,
              color: "var(--text)"
            }}>
              {v.brand}
            </div>
            <div style={{
              fontSize: "13px",
              color: "var(--text-light)",
              marginTop: 4,
              fontWeight: 500
            }}>
              {v.type} • {v.year}
            </div>
          </div>
          <span style={{
            backgroundColor: "rgba(76, 175, 80, 0.1)",
            color: "var(--primary)",
            padding: "6px 12px",
            borderRadius: "4px",
            fontSize: "12px",
            fontWeight: 600,
            textTransform: "capitalize",
            whiteSpace: "nowrap"
          }}>
            {v.status || "Available"}
          </span>
        </div>

        {/* Divider */}
        <div style={{ height: "1px", backgroundColor: "var(--border)" }} />

        {/* Details */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", gap: 12 }}>
          <InfoRow label="Price" value={`LKR ${Number(v.price || 0).toLocaleString()}`} />
          <InfoRow label="Vehicle No." value={v.vehicleNumber || "-"} />
          {v.details && (
            <InfoRow 
              label="Details" 
              value={v.details.length > 60 ? v.details.substring(0, 60) + "..." : v.details} 
            />
          )}
        </div>

        {/* Actions */}
        <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginTop: "auto" }}>
          <button
            className="btn btnPrimary"
            onClick={() => navigate(`/vehicles/${v._id}`)}
            style={{ flex: 1, minWidth: 120 }}
          >
            View Details
          </button>
          <button
            className="btn"
            onClick={() => navigate("/book-appointment", { state: { vehicleId: v._id } })}
            style={{ flex: 1, minWidth: 120 }}
          >
            Book Drive
          </button>
        </div>
      </div>
    </div>
  );
}

function InfoRow({ label, value }) {
  return (
    <div style={{ display: "flex", justifyContent: "space-between", gap: 12 }}>
      <div style={{ fontSize: "12px", fontWeight: 600, color: "var(--text-light)", textTransform: "uppercase" }}>
        {label}
      </div>
      <div style={{
        fontSize: "13px",
        fontWeight: 600,
        color: "var(--text)",
        textAlign: "right"
      }}>
        {value}
      </div>
    </div>
  );
}

export default Home;
